const items = $input.all();
const results = [];

for (const item of items) {
  const msg = item.json;

  const emailId = msg.id || msg.emailId || msg.messageId || '';
  const threadId = msg.threadId || '';

  // Extract headers from raw Gmail API format
  const headers = (msg.payload && msg.payload.headers) ? msg.payload.headers : [];
  const getHeader = (name) => {
    const h = headers.find(h => h.name && h.name.toLowerCase() === name.toLowerCase());
    return h ? h.value : '';
  };

  // SUBJECT
  let subject = '';
  if (msg.subject && typeof msg.subject === 'string') subject = msg.subject;
  if (!subject) subject = getHeader('Subject');
  if (!subject && msg.headers && msg.headers.subject) subject = msg.headers.subject;
  if (!subject && msg.headers && msg.headers.Subject) subject = msg.headers.Subject;
  if (!subject) {
    for (const key of Object.keys(msg)) {
      if (key.toLowerCase() === 'subject' && typeof msg[key] === 'string' && msg[key]) {
        subject = msg[key]; break;
      }
    }
  }
  if (!subject) subject = '(no subject)';

  // FROM
  let from = '';
  if (msg.from && typeof msg.from === 'string') from = msg.from;
  if (!from && msg.sender && typeof msg.sender === 'string') from = msg.sender;
  if (!from) from = getHeader('From');
  if (!from && msg.headers && msg.headers.from) from = msg.headers.from;
  if (!from && msg.headers && msg.headers.From) from = msg.headers.From;
  if (!from) {
    for (const key of Object.keys(msg)) {
      if (key.toLowerCase() === 'from' && typeof msg[key] === 'string' && msg[key]) {
        from = msg[key]; break;
      }
    }
  }
  if (!from) from = '(unknown sender)';

  // BODY TEXT: get raw HTML first for link extraction
  let rawHtml = '';
  let rawText = '';
  const htmlFields = ['textHtml', 'text_html', 'html'];
  const textFields = ['text', 'textPlain', 'text_plain', 'body', 'content'];
  for (const f of htmlFields) {
    if (msg[f] && typeof msg[f] === 'string' && msg[f].length > 20) { rawHtml = msg[f]; break; }
  }
  for (const f of textFields) {
    if (msg[f] && typeof msg[f] === 'string' && msg[f].length > 20) { rawText = msg[f]; break; }
  }
  if (!rawHtml && !rawText && msg.payload) {
    const extractBody = (payload, mime) => {
      if (!payload) return '';
      if (payload.mimeType && payload.mimeType.includes(mime) && payload.body && payload.body.data) {
        try { return Buffer.from(payload.body.data, 'base64').toString('utf-8'); } catch(e) { return ''; }
      }
      if (payload.parts && Array.isArray(payload.parts)) {
        for (const part of payload.parts) { const t = extractBody(part, mime); if (t) return t; }
      }
      return '';
    };
    rawHtml = extractBody(msg.payload, 'html');
    if (!rawText) rawText = extractBody(msg.payload, 'plain');
  }
  if (!rawHtml && !rawText && msg.snippet) rawText = msg.snippet;

  // EXTRACT LINKS from HTML before stripping
  const links = [];
  const linkSource = rawHtml || rawText || '';
  const hrefRegex = /href="([^"]+)"/gi;
  let hrefMatch;
  while ((hrefMatch = hrefRegex.exec(linkSource)) !== null) {
    const url = hrefMatch[1];
    if (url && url.startsWith('http') && !url.includes('unsubscribe') && !url.includes('mailto:') && !url.includes('list-manage') && !url.includes('tracking') && !url.includes('click.') && !url.includes('open.') && url.length > 10) {
      links.push(url);
    }
  }
  // Also extract plain text URLs
  const urlRegex = /https?:\/\/[^\s<>"'\)\]]+/gi;
  let urlMatch;
  const plainText = rawText || '';
  while ((urlMatch = urlRegex.exec(plainText)) !== null) {
    const url = urlMatch[0];
    if (!url.includes('unsubscribe') && !url.includes('mailto:') && !links.includes(url)) {
      links.push(url);
    }
  }
  // Find the best candidature/application link
  let applicationLink = '';
  const priorityKeywords = ['application', 'candidat', 'status', 'portal', 'career', 'job', 'offer', 'interview', 'dashboard', 'profile', 'workday', 'greenhouse', 'lever', 'ashby', 'icims', 'taleo', 'successfactors', 'smartrecruiters', 'bamboo', 'myworkday', 'jobs.lever', 'boards.greenhouse'];
  for (const link of links) {
    const lower = link.toLowerCase();
    if (priorityKeywords.some(kw => lower.includes(kw))) {
      applicationLink = link;
      break;
    }
  }
  if (!applicationLink && links.length > 0) applicationLink = links[0];

  // Clean text for AI
  let text = (rawHtml || rawText || '').replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
  if (text.length > 2500) text = text.substring(0, 2500);

  // DATE
  let emailDate = new Date().toISOString().split('T')[0];
  if (msg.internalDate) {
    emailDate = new Date(parseInt(msg.internalDate)).toISOString().split('T')[0];
  } else if (msg.date) {
    try { emailDate = new Date(msg.date).toISOString().split('T')[0]; } catch(e) {}
  } else {
    const dateHeader = getHeader('Date');
    if (dateHeader) try { emailDate = new Date(dateHeader).toISOString().split('T')[0]; } catch(e) {}
  }

  results.push({
    json: { emailId, threadId, subject, from, text, emailDate, applicationLink }
  });
}

return results;

const items = $input.all();
const results = [];

for (const item of items) {
  const text = (item.json.text || '').toLowerCase();

  let heuristicStatus = 'unknown';

  if (/unfortunately|regret|not moving forward|we will not|we won't be|not selected|not been selected/.test(text)) {
    heuristicStatus = 'rejected';
  } else if (/please.*offer|pleased to offer|offer letter|we.*offer you|we are offering/.test(text)) {
    heuristicStatus = 'offer';
  } else if (/interview|schedule.*call|schedule.*meeting|your availability|set up.*time|speak with you/.test(text)) {
    heuristicStatus = 'interview';
  } else if (/application received|thank you for applying|we have received your application|successfully submitted/.test(text)) {
    heuristicStatus = 'applied';
  }

  results.push({
    json: { ...item.json, heuristicStatus }
  });
}

return results;

const items = $input.all();
const results = [];
for (const item of items) {
  const data = item.json;
  // Check if we got a rate limit error and have more providers to try
  if ((data.statusCode === 429 || data.error || data.errorMessage) && data.providerPayloads && data.currentProviderIndex < data.providerPayloads.length - 1) {
    // Move to next provider
    results.push({ json: { ...data, currentProviderIndex: data.currentProviderIndex + 1, _retryNeeded: true } });
  } else {
    results.push({ json: { ...data, _retryNeeded: false } });
  }
}
return results;

const items = $input.all();
const results = [];
const defaultFallback = { company: 'unknown', role: 'unknown', status: 'unknown', confidence: 0 };
for (const item of items) {
  let parsed = { ...defaultFallback };
  try {
    const choices = item.json.choices;
    if (choices && choices.length > 0) {
      const content = choices[0].message && choices[0].message.content ? choices[0].message.content : '';
      const cleaned = content.replace(/```json|```/gi, '').trim();
      const candidate = JSON.parse(cleaned);
      const validStatuses = ['applied', 'interview', 'rejected', 'offer', 'unknown'];
      parsed.company = candidate.company || 'unknown';
      parsed.role = candidate.role || 'unknown';
      parsed.status = validStatuses.includes(candidate.status) ? candidate.status : 'unknown';
      parsed.confidence = candidate.confidence || 0;
    }
  } catch (e) {}
  results.push({ json: { ...item.json, aiResult: parsed } });
}
return results;

const items = $input.all();
const results = [];

function extractRole(subject, text) {
  const combined = (subject + ' ' + text).toLowerCase();
  const patterns = [
    /(?:for the (?:role|position) of|application for|applied for|applying for|your application for|the )\s+([A-Za-z][A-Za-z0-9 /&,.-]{2,60}?)(?:\s+(?:position|role|at|with|-))/i,
    /(?:for the (?:role|position) of|application for|applied for|applying for|your application for)\s+([A-Za-z][A-Za-z0-9 /&,.-]{2,60})(?:[.,;!?\n]|$)/i,
    /(?:position|role|job|opening|opportunity)\s*:\s*([A-Za-z][A-Za-z0-9 /&,.-]{2,60})(?:[.,;!?\n]|$)/i
  ];
  for (const p of patterns) {
    const m = combined.match(p);
    if (m && m[1]) {
      let role = m[1].trim().replace(/\s+(at|with|in|for|and|the)$/i, '').trim();
      if (role.length > 2 && role.length < 80) return role.split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
    }
  }
  const subjectClean = subject.replace(/[-–—|:].*(?:application|received|confirmation|update|status|thank|reply|re:)/i, '').trim();
  const roleWords = subjectClean.replace(/^(?:re:|fwd:|fw:)\s*/i, '').trim();
  if (roleWords.length > 3 && roleWords.length < 80 && !/^(?:thank|your|we |hi |hello|dear|update|status|application)/i.test(roleWords)) {
    return roleWords.split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
  }
  return 'unknown';
}

for (const item of items) {
  const data = item.json;

  const heuristicStatus = data.heuristicStatus || 'unknown';
  const aiResult = data.aiResult || { company: 'unknown', role: 'unknown', status: 'unknown', confidence: 0 };

  let finalStatus = 'unknown';
  if (heuristicStatus !== 'unknown') {
    finalStatus = heuristicStatus;
  } else if (aiResult.confidence >= 0.6 && aiResult.status !== 'unknown') {
    finalStatus = aiResult.status;
  }

  if (finalStatus === 'unknown') continue;

  let company = (aiResult.company && aiResult.company !== 'unknown') ? aiResult.company : '';
  if (!company) {
    const fromStr = data.from || '';
    const domainMatch = fromStr.match(/@([^>\s]+)/);
    if (domainMatch) {
      const parts = domainMatch[1].split('.');
      if (parts.length >= 2) {
        company = parts[parts.length - 2];
        company = company.charAt(0).toUpperCase() + company.slice(1);
      }
    }
  }
  if (!company) company = 'unknown';

  let role = (aiResult.role && aiResult.role !== 'unknown') ? aiResult.role : '';
  if (!role) role = extractRole(data.subject || '', data.text || '');

  const emailDate = data.emailDate || new Date().toISOString().split('T')[0];

  const payload = {
    company,
    role,
    status: finalStatus,
    'Application Link': data.applicationLink || '',
    'Last Update Date': emailDate
  };

  if (finalStatus === 'applied') {
    payload['Applied Date'] = emailDate;
  }

  results.push({ json: payload });
}

if (results.length === 0) return [];
return results;

const items = $input.all();
const results = [];

for (const item of items) {
  const payload = item.json;
  const messages = [
    { role: 'system', content: 'You are a final QA validator for a job application tracker. You receive a JSON object with fields: company, role, status, subject, from. Return ONLY valid JSON with no extra text, no markdown: {"isValid": true/false, "reason": "one-line reason"}.

SET isValid=true FOR:
- status="applied": direct confirmation from a company (thank you for applying, application received, we will be in touch)
- status="rejected": direct rejection from a company (unfortunately, not moving forward, we regret to inform, after careful consideration, chosen other candidates)
- status="interview": ANY direct recruiter or company outreach to schedule a call or meeting. This includes: meeting links (Zoom, Google Meet, Teams, Calendly, cal.com, Webex), asking for availability, mentioning interview/screening call/technical round/HR round, saying shortlisted/next steps/we would like to connect. A short informal email from a company recruiter asking for availability is ALWAYS valid.
- status="offer": job offer or offer letter from a company
- status="unknown" but company is known and context is job-related: set isValid=true, it needs manual review
- When in doubt between true and false, always choose true. Missing a real email is worse than including a borderline one.

SET isValid=false FOR:
- Sender domain is a job portal: linkedin.com, naukri.com, instahyre.com, indeed.com, shine.com, foundit.in, monsterindia.com, glassdoor.com, cutshort.io, wellfound.com, angellist.com, iimjobs.com, hirist.com, internshala.com, apna.co, unstop.com, hirect.in, timesjobs.com, freshersworld.com
- Body or subject contains job alert phrases: jobs matching your profile, new jobs for you, job recommendations, your job alert, top jobs this week, companies are hiring, recommended jobs, suggested jobs, people also applied
- Promotional or marketing email with discount/sale language or unsubscribe-heavy content
- status="unknown" AND company="unknown" at the same time
- Email has zero connection to hiring, recruitment, or job applications

EDGE CASES:
- Automated ATS emails from Greenhouse, Lever, Workday, Ashby, BambooHR confirming an application = always isValid=true
- A recruiter emailing from a company domain (not a portal) = always isValid=true regardless of email length or tone
- Do not penalize short or informal emails from real companies' },
    { role: 'user', content: JSON.stringify(payload) }
  ];

  results.push({
    json: {
      ...payload,
      judgingPayload: JSON.stringify({ model: 'llama3.1:8b', temperature: 0, messages, format: 'json' })
    }
  });
}

return results;

const items = $input.all();
let originalItems = [];
try { originalItems = $('Build Judging Payload').all(); } catch(e) { originalItems = $items('Build Judging Payload'); }

const results = [];
const validStatuses = ['applied', 'rejected', 'interview', 'offer'];

for (let i = 0; i < items.length; i++) {
  const data = items[i].json;
  const originalData = originalItems[i].json;

  // If this item is an error response, skip entirely
  if (data.error || data.errorMessage || data.statusCode === 429 || data.statusCode >= 400) continue;

  let isValid = true;

  try {
    if (data.choices && data.choices.length > 0) {
      const content = data.choices[0].message.content;
      const cleaned = content.replace(/```json|```/gi, '').trim();
      const parsed = JSON.parse(cleaned);

      if (parsed.isValid === false) isValid = false;
    }
  } catch (e) {
    // If AI response parse fails, let it through (fail-open)
  }

  if (!isValid) continue;

  // Build clean output with ONLY the columns Sheets expect
  const clean = {
    company: originalData.company || 'unknown',
    role: originalData.role || 'unknown',
    status: validStatuses.includes(originalData.status) ? originalData.status : 'unknown',
    'Application Link': originalData['Application Link'] || '',
    'Last Update Date': originalData['Last Update Date'] || ''
  };
  if (originalData['Applied Date']) clean['Applied Date'] = originalData['Applied Date'];

  // Drop items with unknown status — only valid categories go to Sheets
  if (clean.status === 'unknown') continue;

  results.push({ json: clean });
}

return results;

const items = $input.all();

const counts = { applied: 0, interview: 0, rejected: 0, offer: 0, unknown: 0 };
const total = items.length;

for (const item of items) {
  const status = (item.json.status || 'unknown').toLowerCase();
  if (counts.hasOwnProperty(status)) {
    counts[status]++;
  } else {
    counts.unknown++;
  }
}

const today = new Date().toISOString().split('T')[0];

const summaryText = [
  `📊 Daily Job Application Summary — ${today}`,
  `Total tracked: ${total}`,
  `✅ Applied:    ${counts.applied}`,
  `🗓 Interview:  ${counts.interview}`,
  `❌ Rejected:   ${counts.rejected}`,
  `🎉 Offer:      ${counts.offer}`,
  `❓ Unknown:    ${counts.unknown}`
].join('\n');

return [{ json: { summary: summaryText, counts, total, date: today } }];
